1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    const cells: Cell[] = [{ x: 0, y: 0 }];
10	    expect(nextGeneration(cells)).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (underpopulation)", () => {
13	    const cells: Cell[] = [{ x: 0, y: 0 }, { x: 1, y: 0 }];
14	    expect(nextGeneration(cells)).toEqual([]);
15	  });
16	  it("should keep a block of four cells unchanged (still life)", () => {
17	    const cells: Cell[] = [
18	      { x: 0, y: 0 },
19	      { x: 1, y: 0 },
20	      { x: 0, y: 1 },
21	      { x: 1, y: 1 },
22	    ];
23	    expect(nextGeneration(cells)).toEqual(expect.arrayContaining(cells));
24	    expect(nextGeneration(cells)).toHaveLength(4);
25	  });
26	  it("should rotate a vertical blinker to horizontal", () => {
27	    const cells: Cell[] = [
28	      { x: 0, y: 0 },
29	      { x: 0, y: 1 },
30	      { x: 0, y: 2 },
31	    ];
32	    const expected: Cell[] = [
33	      { x: -1, y: 1 },
34	      { x: 0, y: 1 },
35	      { x: 1, y: 1 },
36	    ];
37	    expect(nextGeneration(cells)).toEqual(expect.arrayContaining(expected));
38	    expect(nextGeneration(cells)).toHaveLength(3);
39	  });
40	  it("should create a new live cell where a dead cell has exactly 3 live neighbors (reproduction)", () => {
41	    const cells: Cell[] = [
42	      { x: 0, y: 2 },
43	      { x: 1, y: 2 },
44	      { x: 0, y: 1 },
45	    ];
46	    const expected: Cell[] = [
47	      { x: 0, y: 2 },
48	      { x: 1, y: 2 },
49	      { x: 0, y: 1 },
50	      { x: 1, y: 1 },
51	    ];
52	    expect(nextGeneration(cells)).toEqual(expect.arrayContaining(expected));
53	    expect(nextGeneration(cells)).toHaveLength(4);
54	  });
55	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
56	  it.todo("should handle negative coordinates");
57	});
58

1	export type Cell = { x: number; y: number };
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = (x: number, y: number) => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const aliveKeys = new Set(cells.map((c) => keyOf(c.x, c.y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const cell of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = { x: cell.x + dx, y: cell.y + dy };
18	      const k = keyOf(neighbor.x, neighbor.y);
19	      const entry = neighborCounts.get(k);
20	      neighborCounts.set(k, { cell: neighbor, count: (entry?.count ?? 0) + 1 });
21	    }
22	  }
23	
24	  const survives = (k: string, count: number) =>
25	    aliveKeys.has(k) ? count === 2 || count === 3 : count === 3;
26	
27	  const result: Cell[] = [];
28	  for (const [k, { cell, count }] of neighborCounts) {
29	    if (survives(k, count)) result.push(cell);
30	  }
31	  return result;
32	}
